    inner class WebAppInterface {
        @JavascriptInterface
        fun getLocalStorage(key: String): String {
            return try {
                val prefs = context.getSharedPreferences("webapp_storage", Context.MODE_PRIVATE)
                prefs.getString(key, "") ?: ""
            } catch (e: Exception) {
                ""
            }
        }
        
        @JavascriptInterface
        fun setLocalStorage(key: String, value: String) {
            try {
                val prefs = context.getSharedPreferences("webapp_storage", Context.MODE_PRIVATE)
                with(prefs.edit()) {
                    putString(key, value)
                    apply()
                }
            } catch (e: Exception) {
                // Handle error
            }
        }
        
        @JavascriptInterface
        fun requestCameraAccess() {
            try {
                val intent = Intent(MediaStore.ACTION_IMAGE_CAPTURE)
                currentCameraFile = createImageFile()
                if (currentCameraFile != null) {
                    intent.putExtra(MediaStore.EXTRA_OUTPUT, Uri.fromFile(currentCameraFile))
                    cameraIntent = intent
                    // Start activity using context from parent class
                    context.startActivity(intent)
                }
            } catch (e: IOException) {
                Toast.makeText(context, "Error accessing camera", Toast.LENGTH_SHORT).show()
            }
        }
        
        @JavascriptInterface
        fun sendPushNotification(title: String, body: String) {
            try {
